import { FplEntry, FplHistory, WrappedData, ChipInfo, PlayerLoyalty, PlayerPerformance, CaptaincyStat } from '../types';

const FPL_BASE_URL = 'https://fantasy.premierleague.com/api';

const PROXY_URLS = [
    'https://api.allorigins.win/raw?url=',
    'https://corsproxy.io/?',
    'https://api.codetabs.com/v1/proxy?quest=',
    'https://thingproxy.freeboard.io/fetch/'
];

async function fetchWithRetry(targetUrl: string): Promise<any> {
    for (const proxy of PROXY_URLS) {
        try {
            const fullUrl = `${proxy}${encodeURIComponent(targetUrl)}`;
            const res = await fetch(fullUrl);

            if (res.status === 404) {
                 // 404 is a valid response from FPL (id not found), don't retry with other proxies
                throw { status: 404, message: "Resource not found" };
            }

            if (res.ok) {
                const text = await res.text();
                try {
                    const data = JSON.parse(text);
                    if (data) return data;
                } catch (jsonError) {
                    console.warn(`[Proxy] Invalid JSON from ${proxy} for ${targetUrl}`);
                }
            }
        } catch (e: any) {
            if (e.status === 404) throw e;
            console.warn(`[Proxy] Failed ${proxy} for ${targetUrl}`, e);
        }
    }
    throw new Error("Unable to fetch data from FPL. All proxies failed.");
}

